import{_ as a}from"./chunks/01_full_ui.B4gjPzCJ.js";import{_ as r,o as e,c as d,a2 as o}from"./chunks/framework.CHSDihme.js";const l="/claude-code-token-free/assets/09_slash_command.BskM2ewy.png",i="/claude-code-token-free/assets/09_file_search.7NmbPX1R.png",n="/claude-code-token-free/assets/03_ask_question_and_permission.BXOKrgCN.png",k=JSON.parse('{"title":"Claude Code 桌面端 — 快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"desktop/01-quick-start.md","filePath":"desktop/01-quick-start.md","lastUpdated":1780310001000}'),s={name:"desktop/01-quick-start.md"};function h(c,t,p,u,g,b){return e(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="claude-code-桌面端--快速上手" tabindex="-1">Claude Code 桌面端 — 快速上手 <a class="header-anchor" href="#claude-code-桌面端--快速上手" aria-label="Permalink to &quot;Claude Code 桌面端 — 快速上手&quot;">​</a></h1><blockquote><p>告别纯黑终端，用图形界面释放 Claude Code 的全部潜能。</p></blockquote><p align="center"><a href="#一界面布局">界面布局</a> · <a href="#二对话操作">对话操作</a> · <a href="#三多标签系统">多标签系统</a> · <a href="#四权限控制">权限控制</a> · <a href="#五项目管理">项目管理</a> · <a href="#六模型与提供商">模型与提供商</a> · <a href="#七im-适配器接入">IM 适配器</a> · <a href="#八定时任务">定时任务</a></p><hr><h2 id="一界面布局" tabindex="-1">一、界面布局 <a class="header-anchor" href="#一界面布局" aria-label="Permalink to &quot;一、界面布局&quot;">​</a></h2><p><img src="'+a+'" alt="桌面端界面总览"></p><p>桌面端采用<strong>三栏 + 标签页</strong>的经典 IDE 布局，从左到右分为：</p><table tabindex="0"><thead><tr><th>区域</th><th>位置</th><th>功能</th></tr></thead><tbody><tr><td><strong>侧边栏</strong></td><td>左侧</td><td>会话列表、项目筛选、搜索、导航入口</td></tr><tr><td><strong>标签栏</strong></td><td>顶部</td><td>多标签切换、拖拽排序、右键菜单</td></tr><tr><td><strong>内容区</strong></td><td>中央</td><td>对话界面 / 设置页 / 任务页</td></tr><tr><td><strong>状态栏</strong></td><td>底部</td><td>当前项目名、模型名称</td></tr></tbody></table><h3 id="侧边栏" tabindex="-1">侧边栏 <a class="header-anchor" href="#侧边栏" aria-label="Permalink to &quot;侧边栏&quot;">​</a></h3><p>侧边栏是你与 Claude Code 交互的导航中心：</p><ul><li><strong>品牌区域</strong>：显示「Claude Code token free」标识，点击 GitHub 图标跳转仓库</li><li><strong>操作按钮</strong>： <ul><li><code>+</code> 新建会话</li><li>时钟图标 → 定时任务管理</li><li>齿轮图标 → 设置页面</li></ul></li><li><strong>项目筛选器</strong>：按工作目录过滤会话列表</li><li><strong>搜索框</strong>：实时搜索会话标题（不区分大小写）</li><li><strong>会话列表</strong>：按时间自动分组 —— 今天 / 昨天 / 最近 7 天 / 最近 30 天 / 更早</li></ul><p><strong>右键菜单</strong>：在会话项上右键可以 <strong>重命名</strong> 或 <strong>删除</strong> 会话。</p><h3 id="状态栏" tabindex="-1">状态栏 <a class="header-anchor" href="#状态栏" aria-label="Permalink to &quot;状态栏&quot;">​</a></h3><p>底部状态栏显示当前会话的项目路径和正在使用的 AI 模型名称，一目了然。</p><hr><h2 id="二对话操作" tabindex="-1">二、对话操作 <a class="header-anchor" href="#二对话操作" aria-label="Permalink to &quot;二、对话操作&quot;">​</a></h2><h3 id="新建会话" tabindex="-1">新建会话 <a class="header-anchor" href="#新建会话" aria-label="Permalink to &quot;新建会话&quot;">​</a></h3><ol><li>点击侧边栏 <code>+</code> 按钮，或使用快捷键 <code>Cmd/Ctrl + N</code></li><li>在空白会话页选择<strong>工作目录</strong>（关联本地项目文件夹）</li><li>输入第一条消息开始对话</li></ol><h3 id="发送消息" tabindex="-1">发送消息 <a class="header-anchor" href="#发送消息" aria-label="Permalink to &quot;发送消息&quot;">​</a></h3><p>在底部输入框编写消息：</p><ul><li><strong>Enter</strong> → 发送消息</li><li><strong>Shift + Enter</strong> → 换行（多行输入）</li><li>输入框会自动调整高度（最高 200px）</li></ul><h3 id="附件上传" tabindex="-1">附件上传 <a class="header-anchor" href="#附件上传" aria-label="Permalink to &quot;附件上传&quot;">​</a></h3><p>桌面端支持多种附件方式：</p><table tabindex="0"><thead><tr><th>方式</th><th>操作</th></tr></thead><tbody><tr><td><strong>粘贴图片</strong></td><td>在输入框中 <code>Cmd/Ctrl + V</code> 粘贴剪贴板图片</td></tr><tr><td><strong>拖拽上传</strong></td><td>将文件拖入输入区域</td></tr><tr><td><strong>文件选择</strong></td><td>点击 <code>+</code> 按钮 → 「添加文件」</td></tr></tbody></table><p>附件会在输入框上方以缩略图画廊展示，支持预览和移除。</p><h3 id="斜杠命令" tabindex="-1">斜杠命令 <a class="header-anchor" href="#斜杠命令" aria-label="Permalink to &quot;斜杠命令&quot;">​</a></h3><p><img src="'+l+`" alt="斜杠命令菜单"></p><p>输入 <code>/</code> 触发命令自动补全菜单：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/commit       — 提交代码</span></span>
<span class="line"><span>/review-pr    — 审查 PR</span></span>
<span class="line"><span>/memory       — 管理记忆</span></span>
<span class="line"><span>/debug        — 调试模式</span></span>
<span class="line"><span>...</span></span></code></pre></div><ul><li><strong>上下箭头</strong> 导航选项</li><li><strong>Enter / Tab</strong> 确认选择</li><li><strong>Esc</strong> 关闭菜单</li><li>命令列表由服务端动态提供，支持搜索过滤</li></ul><h3 id="-文件引用" tabindex="-1">@ 文件引用 <a class="header-anchor" href="#-文件引用" aria-label="Permalink to &quot;@ 文件引用&quot;">​</a></h3><p><img src="`+i+'" alt="文件搜索菜单"></p><p>输入 <code>@</code> 触发文件搜索菜单，快速将文件引入对话上下文：</p><ul><li>支持路径和文件名自动补全</li><li>上下箭头导航、Enter 选择</li></ul><h3 id="消息类型" tabindex="-1">消息类型 <a class="header-anchor" href="#消息类型" aria-label="Permalink to &quot;消息类型&quot;">​</a></h3><p>对话中会展示多种消息类型：</p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>展示形式</th></tr></thead><tbody><tr><td><strong>用户消息</strong></td><td>你发送的文本和附件</td><td>用户头像 + 消息气泡</td></tr><tr><td><strong>助手消息</strong></td><td>AI 回复内容</td><td>带边框气泡 + Markdown 渲染</td></tr><tr><td><strong>思考块</strong></td><td>AI 的推理过程（Extended Thinking）</td><td>可展开/折叠，显示思考预览</td></tr><tr><td><strong>工具调用</strong></td><td>Bash、Edit、Read 等工具操作</td><td>工具图标 + 可展开详情</td></tr><tr><td><strong>工具结果</strong></td><td>工具执行的输出</td><td>代码块展示，带成功/错误状态</td></tr><tr><td><strong>权限请求</strong></td><td>需要用户审批的操作</td><td>交互式对话框，含允许/拒绝按钮</td></tr><tr><td><strong>AskUser</strong></td><td>AI 向你提问</td><td>特殊输入框</td></tr></tbody></table><h3 id="流式输出" tabindex="-1">流式输出 <a class="header-anchor" href="#流式输出" aria-label="Permalink to &quot;流式输出&quot;">​</a></h3><p>AI 回复时实时流式展示，支持：</p><ul><li>打字效果的闪烁光标 <code>▍</code></li><li>流式代码高亮（使用 Shiki 引擎，VS Code 级别语法着色）</li><li>随时可点击 <strong>停止</strong> 按钮（或 <code>Cmd/Ctrl + .</code>）中断生成</li></ul><h3 id="消息操作" tabindex="-1">消息操作 <a class="header-anchor" href="#消息操作" aria-label="Permalink to &quot;消息操作&quot;">​</a></h3><p>悬浮在消息上时，右下角出现操作栏：</p><ul><li><strong>复制</strong> — 复制消息文本内容</li></ul><hr><h2 id="三多标签系统" tabindex="-1">三、多标签系统 <a class="header-anchor" href="#三多标签系统" aria-label="Permalink to &quot;三、多标签系统&quot;">​</a></h2><p>桌面端支持同时打开多个对话标签，像浏览器一样管理会话。</p><h3 id="标签操作" tabindex="-1">标签操作 <a class="header-anchor" href="#标签操作" aria-label="Permalink to &quot;标签操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>方式</th></tr></thead><tbody><tr><td><strong>新建标签</strong></td><td><code>Cmd/Ctrl + N</code> 或点击 <code>+</code></td></tr><tr><td><strong>切换标签</strong></td><td>点击目标标签</td></tr><tr><td><strong>关闭标签</strong></td><td>悬浮标签 → 点击 <code>×</code></td></tr><tr><td><strong>拖拽排序</strong></td><td>按住标签拖动到目标位置</td></tr><tr><td><strong>左右滚动</strong></td><td>标签过多时出现滚动箭头</td></tr></tbody></table><h3 id="标签状态指示" tabindex="-1">标签状态指示 <a class="header-anchor" href="#标签状态指示" aria-label="Permalink to &quot;标签状态指示&quot;">​</a></h3><ul><li><strong>绿色脉冲点</strong> → 会话正在运行</li><li><strong>红色点</strong> → 会话出错</li><li><strong>无标记</strong> → 会话空闲</li></ul><h3 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h3><p>右键标签打开上下文菜单：</p><ul><li>关闭当前标签</li><li>关闭其他标签</li><li>关闭左侧标签</li><li>关闭右侧标签</li><li>关闭全部标签</li></ul><h3 id="关闭保护" tabindex="-1">关闭保护 <a class="header-anchor" href="#关闭保护" aria-label="Permalink to &quot;关闭保护&quot;">​</a></h3><p>当关闭一个<strong>正在运行的会话标签</strong>时，会弹出确认对话框：</p><ul><li><strong>继续运行</strong> — 保留标签</li><li><strong>停止并关闭</strong> — 终止会话后关闭</li><li><strong>取消</strong> — 放弃操作</li></ul><p>标签状态自动保存到 <code>localStorage</code>，下次启动时恢复。</p><hr><h2 id="四权限控制" tabindex="-1">四、权限控制 <a class="header-anchor" href="#四权限控制" aria-label="Permalink to &quot;四、权限控制&quot;">​</a></h2><p><img src="'+n+'" alt="权限请求与 AI 提问"></p><p>Claude Code 在执行文件修改、Shell 命令等操作前，会请求你的权限。</p><h3 id="权限请求对话框" tabindex="-1">权限请求对话框 <a class="header-anchor" href="#权限请求对话框" aria-label="Permalink to &quot;权限请求对话框&quot;">​</a></h3><p>当 AI 需要执行敏感操作时，会弹出权限请求卡片，显示：</p><ul><li>工具类型（如 Bash、Edit、Write）</li><li>操作预览（命令内容、Diff 变更等）</li><li>详细输入参数（可展开查看）</li></ul><p>你可以选择：</p><table tabindex="0"><thead><tr><th>按钮</th><th>效果</th></tr></thead><tbody><tr><td><strong>允许</strong></td><td>仅本次允许执行</td></tr><tr><td><strong>一直允许</strong></td><td>本次会话内自动允许同类操作</td></tr><tr><td><strong>拒绝</strong></td><td>拒绝本次执行</td></tr></tbody></table><h3 id="四种权限模式" tabindex="-1">四种权限模式 <a class="header-anchor" href="#四种权限模式" aria-label="Permalink to &quot;四种权限模式&quot;">​</a></h3><p>在设置中可切换全局权限模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>询问权限</strong> (default)</td><td>每个操作都需确认</td><td>安全第一</td></tr><tr><td><strong>自动接受</strong> (acceptEdits)</td><td>自动允许编辑操作</td><td>信任文件修改</td></tr><tr><td><strong>计划模式</strong> (plan)</td><td>只展示计划不执行</td><td>审查方案</td></tr><tr><td><strong>绕过权限</strong> (bypassPermissions)</td><td>全部自动执行</td><td>完全信任（需二次确认）</td></tr></tbody></table><blockquote><p>切换到「绕过权限」时需要确认警告对话框，防止误操作。</p></blockquote><hr><h2 id="五项目管理" tabindex="-1">五、项目管理 <a class="header-anchor" href="#五项目管理" aria-label="Permalink to &quot;五、项目管理&quot;">​</a></h2><p>每个会话都绑定一个<strong>工作目录</strong>，即你的本地项目文件夹。</p><h3 id="工作目录" tabindex="-1">工作目录 <a class="header-anchor" href="#工作目录" aria-label="Permalink to &quot;工作目录&quot;">​</a></h3><ul><li>新建会话时通过 <strong>DirectoryPicker</strong> 选择工作目录</li><li>系统自动检测目录是否存在，不存在时显示警告</li><li>支持 Git 仓库识别，状态栏和会话信息中展示： <ul><li>仓库名称</li><li>当前分支</li><li>项目路径</li></ul></li></ul><h3 id="项目筛选" tabindex="-1">项目筛选 <a class="header-anchor" href="#项目筛选" aria-label="Permalink to &quot;项目筛选&quot;">​</a></h3><p>侧边栏中的 <strong>ProjectFilter</strong> 组件可按项目过滤会话：</p><ol><li>点击项目筛选下拉框</li><li>选择目标项目</li><li>会话列表仅显示该项目的会话</li></ol><h3 id="最近项目" tabindex="-1">最近项目 <a class="header-anchor" href="#最近项目" aria-label="Permalink to &quot;最近项目&quot;">​</a></h3><p>通过 API 获取最近使用的项目列表，包含：</p><ul><li>项目路径和名称</li><li>是否为 Git 仓库</li><li>分支名</li><li>会话数量</li><li>最后修改时间</li></ul><hr><h2 id="六模型与提供商" tabindex="-1">六、模型与提供商 <a class="header-anchor" href="#六模型与提供商" aria-label="Permalink to &quot;六、模型与提供商&quot;">​</a></h2><h3 id="模型选择" tabindex="-1">模型选择 <a class="header-anchor" href="#模型选择" aria-label="Permalink to &quot;模型选择&quot;">​</a></h3><p>点击状态栏的模型名称，或在设置中打开模型选择器：</p><ul><li>显示所有可用模型（带图标区分 Opus/Sonnet/Haiku）</li><li>单选切换当前模型</li><li>支持 <strong>Effort 级别</strong> 调节：Low / Medium / High / Max</li></ul><h3 id="自定义-provider" tabindex="-1">自定义 Provider <a class="header-anchor" href="#自定义-provider" aria-label="Permalink to &quot;自定义 Provider&quot;">​</a></h3><p>在设置 → <strong>Providers</strong> 标签页管理 AI 提供商：</p><h4 id="预设提供商" tabindex="-1">预设提供商 <a class="header-anchor" href="#预设提供商" aria-label="Permalink to &quot;预设提供商&quot;">​</a></h4><p>系统内置多种预设，快速配置：</p><ul><li><strong>Anthropic</strong> — 官方 API</li><li><strong>OpenAI</strong> — GPT 系列</li><li><strong>OpenRouter</strong> — 多模型聚合</li><li><strong>Ollama</strong> — 本地模型</li><li>其他 Anthropic 兼容服务</li></ul><h4 id="配置项" tabindex="-1">配置项 <a class="header-anchor" href="#配置项" aria-label="Permalink to &quot;配置项&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>API Key</td><td>提供商密钥</td></tr><tr><td>Base URL</td><td>API 基础地址</td></tr><tr><td>API 格式</td><td>anthropic / openai_chat / openai_responses</td></tr><tr><td>模型映射</td><td>main / haiku / sonnet / opus 对应的实际模型名</td></tr></tbody></table><h4 id="连接测试" tabindex="-1">连接测试 <a class="header-anchor" href="#连接测试" aria-label="Permalink to &quot;连接测试&quot;">​</a></h4><p>配置完成后可点击 <strong>测试连接</strong>，系统会发送测试请求验证配置是否正确（两步验证：连接性 + 模型可用性）。</p><hr><h2 id="七im-适配器接入" tabindex="-1">七、IM 适配器接入 <a class="header-anchor" href="#七im-适配器接入" aria-label="Permalink to &quot;七、IM 适配器接入&quot;">​</a></h2><p>桌面端不仅提供本地 GUI，还支持通过 <strong>Telegram 和飞书</strong> 远程对话。</p><h3 id="配置步骤" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h3><ol><li>打开设置 → <strong>Adapters</strong> 标签页</li><li>填入平台凭证： <ul><li><strong>Telegram</strong>：Bot Token</li><li><strong>飞书</strong>：App ID + App Secret</li></ul></li><li>配置默认工作目录和允许的用户</li><li>启动适配器进程</li></ol><h3 id="用户配对" tabindex="-1">用户配对 <a class="header-anchor" href="#用户配对" aria-label="Permalink to &quot;用户配对&quot;">​</a></h3><p>为了安全，IM 用户需要通过<strong>配对码</strong>授权：</p><ol><li>在桌面端设置中点击「生成配对码」</li><li>获取一个 <strong>6 位安全字符码</strong>（60 分钟有效、一次性使用）</li><li>在 Telegram/飞书中向 Bot 发送该配对码</li><li>配对成功后即可开始对话</li></ol><p>安全特性：</p><ul><li>排除易混淆字符（0/O/1/I/L）</li><li>同一用户 5 分钟内最多失败 5 次</li><li>密钥在 API 返回时自动脱敏（仅显示后 4 位）</li></ul><h3 id="im-内操作" tabindex="-1">IM 内操作 <a class="header-anchor" href="#im-内操作" aria-label="Permalink to &quot;IM 内操作&quot;">​</a></h3><p>配对成功后，可在 IM 中：</p><table tabindex="0"><thead><tr><th>命令</th><th>效果</th></tr></thead><tbody><tr><td>直接发文本</td><td>与 Claude Code 对话</td></tr><tr><td><code>/new [项目名]</code> 或 <code>新会话</code></td><td>开始新会话（支持模糊匹配项目）</td></tr><tr><td><code>/projects</code> 或 <code>项目列表</code></td><td>查看最近项目</td></tr><tr><td><code>/stop</code> 或 <code>停止</code></td><td>停止当前生成</td></tr></tbody></table><p>权限请求在 IM 中以<strong>按钮卡片</strong>形式展示（Telegram Inline Keyboard / 飞书 Interactive Card），点击即可审批。</p><hr><h2 id="八定时任务" tabindex="-1">八、定时任务 <a class="header-anchor" href="#八定时任务" aria-label="Permalink to &quot;八、定时任务&quot;">​</a></h2><p>桌面端支持创建 <strong>Cron 定时任务</strong>，让 Claude Code 按计划自动执行。</p><h3 id="进入任务管理" tabindex="-1">进入任务管理 <a class="header-anchor" href="#进入任务管理" aria-label="Permalink to &quot;进入任务管理&quot;">​</a></h3><p>点击侧边栏的<strong>时钟图标</strong>进入定时任务页面。</p><p>页面顶部显示统计卡片：总任务数 / 活跃数 / 禁用数。</p><h3 id="创建任务" tabindex="-1">创建任务 <a class="header-anchor" href="#创建任务" aria-label="Permalink to &quot;创建任务&quot;">​</a></h3><p>点击「新建任务」，填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>任务名称</td><td>描述性名称</td></tr><tr><td>提示词</td><td>Claude Code 执行的 Prompt</td></tr><tr><td>Cron 表达式</td><td>执行时间计划</td></tr><tr><td>周日期</td><td>可视化选择执行的星期几</td></tr><tr><td>模型</td><td>使用的 AI 模型</td></tr><tr><td>权限模式</td><td>任务执行时的权限策略</td></tr></tbody></table><h3 id="任务管理" tabindex="-1">任务管理 <a class="header-anchor" href="#任务管理" aria-label="Permalink to &quot;任务管理&quot;">​</a></h3><p>每个任务行显示：</p><ul><li>名称和描述</li><li>Cron 表达式（人性化展示）</li><li>启用/禁用开关</li><li>运行历史（可展开查看）</li><li>手动运行按钮</li><li>删除按钮</li></ul><blockquote><p>注意：定时任务在桌面应用运行时才会执行。</p></blockquote><hr><h2 id="九键盘快捷键速查" tabindex="-1">九、键盘快捷键速查 <a class="header-anchor" href="#九键盘快捷键速查" aria-label="Permalink to &quot;九、键盘快捷键速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Cmd/Ctrl + N</code></td><td>新建会话</td></tr><tr><td><code>Cmd/Ctrl + K</code></td><td>聚焦侧边栏搜索</td></tr><tr><td><code>Cmd/Ctrl + .</code></td><td>停止当前生成</td></tr><tr><td><code>Escape</code></td><td>关闭模态框</td></tr><tr><td><code>Enter</code></td><td>发送消息</td></tr><tr><td><code>Shift + Enter</code></td><td>输入框换行</td></tr><tr><td><code>/</code></td><td>触发斜杠命令菜单</td></tr><tr><td><code>@</code></td><td>触发文件搜索菜单</td></tr></tbody></table><hr><h2 id="十主题与国际化" tabindex="-1">十、主题与国际化 <a class="header-anchor" href="#十主题与国际化" aria-label="Permalink to &quot;十、主题与国际化&quot;">​</a></h2><h3 id="主题切换" tabindex="-1">主题切换 <a class="header-anchor" href="#主题切换" aria-label="Permalink to &quot;主题切换&quot;">​</a></h3><p>在设置中切换 <strong>浅色 / 深色</strong> 主题。</p><p>桌面端采用暖色调设计系统：</p><ul><li>浅色模式：奶油色背景（#FAF9F5）</li><li>深色模式：深色背景</li><li>品牌色：褐红色（#8F482F）</li></ul><h3 id="国际化" tabindex="-1">国际化 <a class="header-anchor" href="#国际化" aria-label="Permalink to &quot;国际化&quot;">​</a></h3><p>支持 <strong>中文</strong> 和 <strong>英文</strong> 两种语言，在设置 → 通用 中切换。</p>',133)])])}const f=r(s,[["render",h]]);export{k as __pageData,f as default};
